```suggestion
                if (const auto& spender_opt{spender.value()}) {
                    UniValue o{make_output(prevout, spender_opt->tx.get(), return_spending_tx)};
                    o.pushKV("blockhash", spender_opt->block_hash.GetHex());
                    result.push_back(std::move(o));
                } else {
                    // Return the input outpoint itself, which indicates it is unspent.
                    result.push_back(make_output(prevout));
